{
  "sentences": [
    {
      "text": "你要不要跟我一起去咖啡店？",
      "pinyin": "Nǐ yào bù yào gēn wǒ yīqǐ qù kāfēidiàn?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 gen1 wo3 yi1qi3 qu4 ka1fei1dian4?",
      "translation_en": "Would you like to go to the coffee shop with me?",
      "translation_ko": "저랑 같이 커피숍에 가실래요?"
    },
    {
      "text": "好啊，我們約下午三點可以嗎？",
      "pinyin": "Hǎo a, wǒmen yuē xiàwǔ sān diǎn kěyǐ ma?",
      "pinyin_numeric": "hao3 a0, wo3men yue1 xia4wu3 san1 dian3 ke3yi3 ma0?",
      "translation_en": "Sure, can we meet at 3 PM?",
      "translation_ko": "좋아요, 오후 3시에 만날까요?"
    },
    {
      "text": "不好意思，我臨時有事，可以改期嗎？",
      "pinyin": "Bù hǎoyìsi, wǒ línshí yǒu shì, kěyǐ gǎiqī ma?",
      "pinyin_numeric": "bu4 hao3yi4si0, wo3 lin2shi2 you3 shi4, ke3yi3 gai3qi1 ma0?",
      "translation_en": "Sorry, something came up. Can we reschedule?",
      "translation_ko": "죄송합니다, 갑자기 일이 생겨서 날짜를 변경할 수 있을까요?"
    },
    {
      "text": "你要不要改天再約？",
      "pinyin": "Nǐ yào bù yào gǎitiān zài yuē?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 gai3tian1 zai4 yue1?",
      "translation_en": "Would you like to schedule another day?",
      "translation_ko": "다른 날 다시 약속하실래요?"
    },
    {
      "text": "沒問題啊，我們下次再約時間。",
      "pinyin": "Méi wèntí a, wǒmen xiàcì zài yuē shíjiān.",
      "pinyin_numeric": "mei2 wen4ti2 a0, wo3men xia4ci4 zai4 yue1 shi2jian1.",
      "translation_en": "No problem, let's set a time next time.",
      "translation_ko": "문제없어요, 다음에 시간을 다시 정해요."
    },
    {
      "text": "你要不要提早到餐廳門口碰面？",
      "pinyin": "Nǐ yào bù yào tízǎo dào cāntīng ménkǒu pèngmiàn?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 ti2zao3 dao4 can1ting1 men2kou3 peng4mian4?",
      "translation_en": "Would you like to meet early at the restaurant entrance?",
      "translation_ko": "일찍 식당 입구에서 만날래요?"
    },
    {
      "text": "抱歉，我那天沒空，可以取消約會嗎？",
      "pinyin": "Bàoqiàn, wǒ nèitiān méi kòng, kěyǐ qǔxiāo yuēhuì ma?",
      "pinyin_numeric": "bao4qian4, wo3 nei4tian1 mei2 kong4, ke3yi3 qu3xiao1 yue1hui4 ma0?",
      "translation_en": "Sorry, I'm busy that day. Can we cancel the date?",
      "translation_ko": "죄송합니다, 그날 시간이 안 돼서 약속을 취소할 수 있을까요?"
    },
    {
      "text": "你要不要延後到晚上七點？",
      "pinyin": "Nǐ yào bù yào yánhòu dào wǎnshàng qī diǎn?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 yan2hou4 dao4 wan3shang4 qi1 dian3?",
      "translation_en": "Would you like to postpone it to 7 PM?",
      "translation_ko": "저녁 7시로 연기하실래요?"
    },
    {
      "text": "好啊，我們約在電影院前面見面。",
      "pinyin": "Hǎo a, wǒmen yuē zài diànyǐngyuàn qiánmiàn jiànmiàn.",
      "pinyin_numeric": "hao3 a0, wo3men yue1 zai4 dian4ying3yuan4 qian2mian4 jian4mian4.",
      "translation_en": "Sure, let's meet in front of the movie theater.",
      "translation_ko": "좋아요, 영화관 앞에서 만나요."
    },
    {
      "text": "你要不要先傳訊息再打電話？",
      "pinyin": "Nǐ yào bù yào xiān chuán xùnxī zài dǎ diànhuà?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 xian1 chuan2 xun4xi1 zai4 da3 dian4hua4?",
      "translation_en": "Would you like to send a message first and then call?",
      "translation_ko": "먼저 메시지를 보내고 전화하실래요?"
    }
  ]
}
